一、标注工具（labelimg****） 1.下载地址 2.双击运行 3.保存后的文件为xml格式 二、下载编译darknet 安装环境 系统：archlinux 显卡：nvidia-smi 12345678910111213141516171819+-----------------------------------------------------------------------------------------+| NVIDIA-SMI 550.120 Driver Version: 550.120 CUDA Version: 12.4 ||-----------------------------------------+------------------------+----------------------+| GPU Name Persistence-M | Bus-Id Disp.A | Volatile Uncorr. ECC || Fan Temp Perf Pwr:Usage/Cap | Memory-Usage | GPU-Util Compute M. || | | MIG M. ||=========================================+========================+======================|| 0 NVIDIA GeForce 920MX Off | 00000000:01:00.0 Off | N/A || N/A 46C P0 N/A / 200W | 0MiB / 2048MiB | 0% Default || | | N/A |+-----------------------------------------+------------------------+----------------------+ +-----------------------------------------------------------------------------------------+| Processes: || GPU GI CI PID Type Process name GPU Memory || ID ID Usage ||=========================================================================================|| No running processes found |+-----------------------------------------------------------------------------------------+ cuda：extra&#x2F;cuda 12.6.1-1 (1.7 GiB 4.7 GiB) cuda安装 yay -s cuda 1.拉取darknet 12git clone https://github.com/pjreddie/darknetcd darknet 2.修改配置文件Makefile（如何使用gpu可参考） 12345678910111213141516171819202122232425GPU=1 #如果使用GPU设置为1，CPU设置为0CUDNN=1 #如果使用CUDNN设置为1，否则为0OPENCV=0 #如果调用摄像头，还需要设置OPENCV为1，否则为0OPENMP=0 #如果使用OPENMP设置为1，否则为0DEBUG=0 #如果使用DEBUG设置为1，否则为0#注释掉不支持的平台#ARCH= -gencode arch=compute_30,code=sm_30 \# -gencode arch=compute_35,code=sm_35 \ARCH= -gencode arch=compute_50,code=[sm_50,compute_50] \ -gencode arch=compute_52,code=[sm_52,compute_52]# -gencode arch=compute_20,code=[sm_20,sm_21] \ This one is deprecated?#修改编译器为GCC13CC=gcc-13CPP=g++-13NVCC=/opt/cuda/bin/nvcc AR=gcc-ar-13ARFLAGS=rcsOPTS=-OfastLDFLAGS= -lm -pthread COMMON= -I/usr/lib/gcc/x86_64-pc-linux-gnu/13.3.0/include/c++/x86_64-pc-linux-gnu/ -I/usr/lib/gcc/x86_64-pc-linux-gnu/13.3.0/include/c++/ -Iinclude/ -Isrc/CFLAGS=-Wall -Wno-unused-result -Wno-unknown-pragmas -Wfatal-errors -fPIC -Wno-deprecated-gpu-targets 3.开始编译 1make 4.下载yolov3预训练模型 1wget https://pjreddie.com/media/files/yolov3.weights 5.测试 1./darknet detect cfg/yolov3.cfg yolov3.weights data/dog.jpg 或者 1./darknet detector test cfg/coco.data cfg/yolov3.cfg yolov3.weights data/dog.jpg 官网链接 运行错误 run yolov3 with GPU:CUDA Error: out of memory My solution to run Yolov3 perfectly was to : modify the cfg&#x2F;yolov3.cfg : 1234batch=1subdivisions=1width=416height=416 Layer before convolutional layer must output image.: No such file or directory 三、准备数据集、训练、测试 1.在darknet目录下创建myData文件夹，目录结构如下，将之前标注好的图片和xml文件放到对应目录下 123456myData ...JPEGImages#存放图像 ...Annotations#存放图像对应的xml文件 ...ImageSets/Main # 存放训练/验证图像的名字（格式如 000001.jpg或者000001），里面包括train.txt。这里给出的格式是: 000000，因为下面的代码中给出了图像的格式。 将自己的数据集图片拷贝到JPEGImages目录下。将数据集label文件拷贝到Annotations目录下。在myData下创建test.py，将下面代码拷贝进去运行，将生成四个文件：train.txt,val.txt,test.txt和trainval.txt。 1234567891011121314151617181920212223242526272829303132333435import osimport randomtrainval_percent = 0.1train_percent = 0.9xmlfilepath = &#x27;Annotations&#x27;txtsavepath = &#x27;ImageSets\Main&#x27;total_xml = os.listdir(xmlfilepath)num = len(total_xml)list = range(num)tv = int(num * trainval_percent)tr = int(tv * train_percent)trainval = random.sample(list, tv)train = random.sample(trainval, tr)ftrainval = open(&#x27;ImageSets/Main/trainval.txt&#x27;, &#x27;w&#x27;)ftest = open(&#x27;ImageSets/Main/test.txt&#x27;, &#x27;w&#x27;)ftrain = open(&#x27;ImageSets/Main/train.txt&#x27;, &#x27;w&#x27;)fval = open(&#x27;ImageSets/Main/val.txt&#x27;, &#x27;w&#x27;)for i in list: name = total_xml[i][:-4] + &#x27;
&#x27; if i in trainval: ftrainval.write(name) if i in train: ftest.write(name) else: fval.write(name) else: ftrain.write(name)ftrainval.close()ftrain.close()fval.close()ftest.close() 运行test.py 2.将数据转换成darknet支持的格式 yolov3提供了将VOC数据集转为YOLO训练所需要的格式的代码，在scripts&#x2F;voc_label.py文件中。这里提供一个修改版本的。在darknet文件夹下新建一个my_lables.py文件，内容如下： 12345678910111213141516171819202122232425262728293031323334353637383940414243444546474849505152535455import xml.etree.ElementTree as ETimport pickleimport osfrom os import listdir, getcwdfrom os.path import join #源代码sets=[(&#x27;2012&#x27;, &#x27;train&#x27;), (&#x27;2012&#x27;, &#x27;val&#x27;), (&#x27;2007&#x27;, &#x27;train&#x27;), (&#x27;2007&#x27;, &#x27;val&#x27;), (&#x27;2007&#x27;, &#x27;test&#x27;)]sets=[(&#x27;myData&#x27;, &#x27;train&#x27;)] # 改成自己建立的myData classes = [&quot;person&quot;, &quot;foot&quot;, &quot;face&quot;] # 改成自己的类别 def convert(size, box): dw = 1./(size[0]) dh = 1./(size[1]) x = (box[0] + box[1])/2.0 - 1 y = (box[2] + box[3])/2.0 - 1 w = box[1] - box[0] h = box[3] - box[2] x = x*dw w = w*dw y = y*dh h = h*dh return (x,y,w,h) def convert_annotation(year, image_id): in_file = open(&#x27;myData/Annotations/%s.xml&#x27;%(image_id)) # 源代码VOCdevkit/VOC%s/Annotations/%s.xml out_file = open(&#x27;myData/labels/%s.txt&#x27;%(image_id), &#x27;w&#x27;) # 源代码VOCdevkit/VOC%s/labels/%s.txt tree=ET.parse(in_file) root = tree.getroot() size = root.find(&#x27;size&#x27;) w = int(size.find(&#x27;width&#x27;).text) h = int(size.find(&#x27;height&#x27;).text) for obj in root.iter(&#x27;object&#x27;): difficult = obj.find(&#x27;difficult&#x27;).text cls = obj.find(&#x27;name&#x27;).text if cls not in classes or int(difficult)==1: continue cls_id = classes.index(cls) xmlbox = obj.find(&#x27;bndbox&#x27;) b = (float(xmlbox.find(&#x27;xmin&#x27;).text), float(xmlbox.find(&#x27;xmax&#x27;).text), float(xmlbox.find(&#x27;ymin&#x27;).text), float(xmlbox.find(&#x27;ymax&#x27;).text)) bb = convert((w,h), b) out_file.write(str(cls_id) + &quot; &quot; + &quot; &quot;.join([str(a) for a in bb]) + &#x27;
&#x27;) wd = getcwd() for year, image_set in sets: if not os.path.exists(&#x27;myData/labels/&#x27;): # 改成自己建立的myData os.makedirs(&#x27;myData/labels/&#x27;) image_ids = open(&#x27;myData/ImageSets/Main/%s.txt&#x27;%(image_set)).read().strip().split() list_file = open(&#x27;myData/%s_%s.txt&#x27;%(year, image_set), &#x27;w&#x27;) for image_id in image_ids: list_file.write(&#x27;%s/myData/JPEGImages/%s.jpg
&#x27;%(wd, image_id)) convert_annotation(year, image_id) list_file.close() 3.运行该脚本 1python my_lables.py 会在.&#x2F;myData目录下生成一个labels文件夹一个txt文件(myData_train.txt)(内容是: 类别的编码和目标的相对位置)。 lables文件中的‘txt文件的含义为： 同理如果要生成训练数据 sets&#x3D;[(‘myData’, ‘train’)] 改为sets&#x3D;[(‘myData’, ‘train’), (‘myData’, ‘test’)] 具体的每一个值的计算方式是这样的：假设一个标注的boundingbox的左下角和右上角坐标分别为（x1,y1）(x2,y2)，图像的宽和高分别为w,h 归一化的中心点x坐标计算公式：（(x2+x1) &#x2F; 2.0）&#x2F; w 归一化的中心点y坐标计算公式：（(y2+y1) &#x2F; 2.0）&#x2F; h 归一化的目标框宽度的计算公式： (x2-x1) &#x2F; w 归一化的目标框高度计算公式：（(y2-y1)&#x2F; h 4.修改darknet&#x2F;cfg下的voc.data和yolov3-voc.cfg文件 为了保险起见，复制这两个文件，并分别重命名为my_data.data和my_yolov3.cfg my_data.data内容： 12345classes= 3 ##改为自己的分类个数##下面都改为自己的路径train = /home/XXX/darknet/myData/myData_train.txt names = /home/XXX/darknet/myData/myData.names #稍后需要创建这个文件backup = /home/XXX/darknet/myData/weights my_yolov3.cfg的内容： &#x2F;yolo, 总共会搜出3个含有yolo的地方。每个地方都必须要改2处， filters：3*（5+len（classes））；其中：classes: len(classes) &#x3D; 3，这里以我的工程为例filters &#x3D; 24classes &#x3D; 3可修改：random &#x3D; 1：原来是1，显存小改为0。（是否要多尺度输出。） 5.可以指定训练批次和训练轮数 123456789101112131415161718192021[net]# Testing ### 测试模式 # batch=1# subdivisions=1# Training ### 训练模式，每次前向的图片数目 = batch/subdivisions batch=64subdivisions=16width=416 ### 网络的输入宽、高、通道数height=416channels=3momentum=0.9 ### 动量 decay=0.0005 ### 权重衰减angle=0saturation = 1.5 ### 饱和度exposure = 1.5 ### 曝光度 hue=.1 ### 色调learning_rate=0.001 ### 学习率 burn_in=1000 ### 学习率控制的参数max_batches = 50200 ### 迭代次数 policy=steps ### 学习率策略 steps=40000,45000 ### 学习率变动步长 因为是训练，所以注释Testing,打开Training，其中 batch&#x3D;64 每batch个样本更新一次参数。 subdivisions&#x3D;16 如果内存不够大，将batch分割为subdivisions个子batch，每个子batch的大小为batch&#x2F;subdivisions。 6.在myData文件夹下新建myData.names文件 123peoplefootcar 7.下载预训练权重 1wget https://pjreddie.com/media/files/darknet53.conv.74 8.开始训练 1./darknet detector train cfg/my_data.data cfg/my_yolov3.cfg darknet53.conv.74 或者指定gpu训练，默认使用gpu0 1./darknet detector train cfg/my_data.data cfg/my_yolov3.cfg darknet53.conv.74 -gups 0,1,2,3 查看gpu信息 从停止处重新训练 1./darknet detector train cfg/my_data.data cfg/my_yolov3.cfg darknet53.conv.74 -gups 0,1,2,3 myData/weights/my_yolov3.backup -gpus 0,1,2,3 9.测试 1./darknet detect cfg/my_yolov3.cfg weights/my_yolov3.weights 1.jpg 10.效果 11.关于opencv调用yolo模型，参考https://www.cnblogs.com/answerThe/p/11486090.html

Windows Python实现方式SplitCap是按照会话流来切割的工具，会话流由源IP、目的IP、源端口、目的端口四个部分组成。 参考github连接： https://github.com/echowei/DeepTraffic/tree/master/1.malware_traffic_classification 该链接有Splitcap工具 1、Split切分会话流Split切分pcap文件脚本（PowerShell）如下： 12345678910111213foreach($f in gci 1_Pcap *.pcap)&#123; 0_Tool\SplitCap_2-1\SplitCap -p 100000 -b 100000 -r $f.FullName -o 2_Session\AllLayers\$($f.BaseName)-ALL # 0_Tool\SplitCap_2-1\SplitCap -p 100000 -b 100000 -r $f.FullName -s flow -o 2_Session\AllLayers\$($f.BaseName)-ALL gci 2_Session\AllLayers\$($f.BaseName)-ALL | ?&#123;$_.Length -eq 0&#125; | del 0_Tool\SplitCap_2-1\SplitCap -p 100000 -b 100000 -r $f.FullName -o 2_Session\L7\$($f.BaseName)-L7 -y L7 # 0_Tool\SplitCap_2-1\SplitCap -p 100000 -b 100000 -r $f.FullName -s flow -o 2_Session\L7\$($f.BaseName)-L7 -y L7 gci 2_Session\L7\$($f.BaseName)-L7 | ?&#123;$_.Length -eq 0&#125; | del&#125;0_Tool inddupe -del 2_Session\AllLayers0_Tool inddupe -del 2_Session\L7 2、提取会话内容对SpiltCap进行预处理，提取传输层以上的payload并进行拼接，脚本（PowerShell）如下： 1234567891011121314151617181920212223242526272829303132333435363738394041424344454647484950515253545556575859606162$SESSIONS_COUNT_LIMIT_MIN = 0$SESSIONS_COUNT_LIMIT_MAX = 6000$TRIMED_FILE_LEN = 784$SOURCE_SESSION_DIR = &quot;2_Session\L7&quot;echo &quot;If Sessions more than $SESSIONS_COUNT_LIMIT_MAX we only select the largest $SESSIONS_COUNT_LIMIT_MAX.&quot;echo &quot;Finally Selected Sessions:&quot;$dirs = gci $SOURCE_SESSION_DIR -Directoryforeach($d in $dirs)&#123; $files = gci $d.FullName $count = $files.count if($count -gt $SESSIONS_COUNT_LIMIT_MIN) &#123; echo &quot;$($d.Name) $count&quot; if($count -gt $SESSIONS_COUNT_LIMIT_MAX) &#123; $files = $files | sort Length -Descending | select -First $SESSIONS_COUNT_LIMIT_MAX $count = $SESSIONS_COUNT_LIMIT_MAX &#125; $files = $files | resolve-path # Ignore the .pcap file that has less than 10 packets $test = $files | get-random -count ([int]($count/10)) $train = $files | ?&#123;$_ -notin $test&#125; $path_test = &quot;3_ProcessedSession\FilteredSession\Test\$($d.Name)&quot; $path_train = &quot;3_ProcessedSession\FilteredSession\Train\$($d.Name)&quot; ni -Path $path_test -ItemType Directory -Force ni -Path $path_train -ItemType Directory -Force cp $test -destination $path_test cp $train -destination $path_train &#125;&#125;echo &quot;All files will be trimed to $TRIMED_FILE_LEN length and if it&#x27;s even shorter we&#x27;ll fill the end with 0x00...&quot;$paths = @((&#x27;3_ProcessedSession\FilteredSession\Train&#x27;, &#x27;3_ProcessedSession\TrimedSession\Train&#x27;), (&#x27;3_ProcessedSession\FilteredSession\Test&#x27;, &#x27;3_ProcessedSession\TrimedSession\Test&#x27;))foreach($p in $paths)&#123; foreach ($d in gci $p[0] -Directory) &#123; ni -Path &quot;$($p[1])\$($d.Name)&quot; -ItemType Directory -Force foreach($f in gci $d.fullname) &#123; $content = [System.IO.File]::ReadAllBytes($f.FullName) $len = $f.length - $TRIMED_FILE_LEN if($len -gt 0) &#123; $content = $content[0..($TRIMED_FILE_LEN-1)] &#125; elseif($len -lt 0) &#123; $padding = [Byte[]] (,0x00 * ([math]::abs($len))) $content = $content += $padding &#125; Set-Content -value $content -encoding byte -path &quot;$($p[1])\$($d.Name)\$($f.Name)&quot; &#125; &#125;&#125; 结果如下，左侧bin文件是提取的会话流，右侧是网络数据流的通信层级，可见绘话流就是TCP层之上的payload。 3、会话流转为png图片文件的内容就是字节序，将字节转为16进制为一个单位的数组，然后将两个数组成员拼接为一个字节，字节转为Int存到numpy的array当中，然后reshape一下，让一行为28个数，Python代码如下： 123456789def getMatrixfrom_pcap(filename,width): with open(filename, &#x27;rb&#x27;) as f: content = f.read() hexst = binascii.hexlify(content) fh = numpy.array([int(hexst[i:i+2],16) for i in range(0, len(hexst), 2)]) rn = int(len(fh)/width) fh = numpy.reshape(fh[:rn*width],(-1,width)) fh = numpy.uint8(fh) return fh 然后在批量处理上一步生成的会话流即可，代码如下： 1234567891011paths = [[&#x27;3_ProcessedSession\TrimedSession\Train&#x27;, &#x27;4_Png\Train&#x27;],[&#x27;3_ProcessedSession\TrimedSession\Test&#x27;, &#x27;4_Png\Test&#x27;]]for p in paths: for i, d in enumerate(os.listdir(p[0])): dir_full = os.path.join(p[1], str(i)) mkdir_p(dir_full) for f in os.listdir(os.path.join(p[0], d)): bin_full = os.path.join(p[0], d, f) print(bin_full) im = Image.fromarray(getMatrixfrom_pcap(bin_full,PNG_SIZE)) png_full = os.path.join(dir_full, os.path.splitext(f)[0]+&#x27;.png&#x27;) im.save(png_full) 4、将PNG图片转为MNIST格式首先MNIST数据集格式查看以下连接： https://blog.csdn.net/qq_20936739&#x2F;article&#x2F;details&#x2F;82011320 文件头： 12345678910111213141516# header for label arrayheader = array(&#x27;B&#x27;)header.extend([0,0,8,1])header.append(int(&#x27;0x&#x27;+hexval[2:][0:2],16))header.append(int(&#x27;0x&#x27;+hexval[2:][2:4],16))header.append(int(&#x27;0x&#x27;+hexval[2:][4:6],16))header.append(int(&#x27;0x&#x27;+hexval[2:][6:8],16)) data_label = header + data_label# additional header for images array if max([width,height]) &lt;= 256: header.extend([0,0,0,width,0,0,0,height])else: raise ValueError(&#x27;Image exceeds maximum size: 256x256 pixels&#x27;);header[3] = 3 # Changing MSB for image data (0x00000803) 数据： 123456789101112for filename in FileList: print(filename) label = int(filename.split(&#x27;\&#x27;)[2]) Im = Image.open(filename) pixel = Im.load() width, height = Im.size for x in range(0,width): for y in range(0,height): data_image.append(pixel[y,x]) data_label.append(label) # labels start (one unsigned byte each)hexval = &quot;&#123;0:#0&#123;1&#125;x&#125;&quot;.format(len(FileList),6) # number of files in HEXhexval = &#x27;0x&#x27; + hexval[2:].zfill(8) 需要改Name，改为Test和Train，如下： 12Names = [[&#x27;4_Png	10k&#x27;,&#x27;5_Mnist\t10k&#x27;]]# Names = [[&#x27;4_Png	rain&#x27;,&#x27;5_Mnist\test&#x27;]] 将PNG数据处理完，生成IDX-Ubyte格式的数据集，便可以根据神经网络来训练： 值得一提的是，如果数据集中只有7个特征的话，数据集标签的维度还是10，10是通过one-hot形式标识的，只是7，8，9位只显示为0。 然后用CNN对其进行训练， 本代码的运行环境如下： tensorflow源码如下： 123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384858687888990919293949596979899100101102103104105106107108109110111112113114115116117118119120121122123124125126import timeimport sysimport numpy as npimport osfrom tensorflow.examples.tutorials.mnist import input_data# start tensorflow interactiveSessionimport tensorflow as tf# Note: if class numer is 2 or 20, please edit the variable named &quot;num_classes&quot; in /usr/local/lib/python2.7/dist-packages/tensorflow/contrib/learn/python/learn/datasets/mnist.py&quot;DATA_DIR = sys.argv[1]CLASS_NUM = int(sys.argv[2])TRAIN_ROUND = int(sys.argv[3])folder = os.path.split(DATA_DIR)[1]sess = tf.InteractiveSession()flags = tf.app.flagsFLAGS = flags.FLAGSflags.DEFINE_string(&#x27;data_dir&#x27;, DATA_DIR, &#x27;Directory for storing data&#x27;)mnist = input_data.read_data_sets(FLAGS.data_dir, one_hot=True)# function: find a element in a listdef find_element_in_list(element, list_element): try: index_element = list_element.index(element) return index_element except ValueError: return -1# weight initializationdef weight_variable(shape): initial = tf.truncated_normal(shape, stddev=0.1) return tf.Variable(initial)def bias_variable(shape): initial = tf.constant(0.1, shape = shape) return tf.Variable(initial)# convolutiondef conv2d(x, W): return tf.nn.conv2d(x, W, strides=[1, 1, 1, 1], padding=&#x27;SAME&#x27;)# poolingdef max_pool_2x2(x): return tf.nn.max_pool(x, ksize=[1, 2, 2, 1], strides=[1, 2, 2, 1], padding=&#x27;SAME&#x27;)# Create the model# placeholderx = tf.placeholder(&quot;float&quot;, [None, 784])y_ = tf.placeholder(&quot;float&quot;, [None, CLASS_NUM])# first convolutinal layerw_conv1 = weight_variable([5, 5, 1, 32])b_conv1 = bias_variable([32])x_image = tf.reshape(x, [-1, 28, 28, 1])h_conv1 = tf.nn.relu(conv2d(x_image, w_conv1) + b_conv1)h_pool1 = max_pool_2x2(h_conv1)# second convolutional layerw_conv2 = weight_variable([5, 5, 32, 64])b_conv2 = bias_variable([64])h_conv2 = tf.nn.relu(conv2d(h_pool1, w_conv2) + b_conv2)h_pool2 = max_pool_2x2(h_conv2)# densely connected layerw_fc1 = weight_variable([7*7*64, 1024])b_fc1 = bias_variable([1024])h_pool2_flat = tf.reshape(h_pool2, [-1, 7*7*64])h_fc1 = tf.nn.relu(tf.matmul(h_pool2_flat, w_fc1) + b_fc1)# dropoutkeep_prob = tf.placeholder(&quot;float&quot;)h_fc1_drop = tf.nn.dropout(h_fc1, keep_prob)# readout layerw_fc2 = weight_variable([1024, CLASS_NUM])b_fc2 = bias_variable([CLASS_NUM])y_conv = tf.nn.softmax(tf.matmul(h_fc1_drop, w_fc2) + b_fc2)# define var&amp;op of training&amp;testingactual_label = tf.argmax(y_, 1)label,idx,count = tf.unique_with_counts(actual_label)cross_entropy = -tf.reduce_sum(y_*tf.log(y_conv))train_step = tf.train.GradientDescentOptimizer(1e-4).minimize(cross_entropy)predict_label = tf.argmax(y_conv, 1)label_p,idx_p,count_p = tf.unique_with_counts(predict_label)correct_prediction = tf.equal(predict_label, actual_label)accuracy = tf.reduce_mean(tf.cast(correct_prediction, &quot;float&quot;))correct_label=tf.boolean_mask(actual_label,correct_prediction)label_c,idx_c,count_c=tf.unique_with_counts(correct_label)# if model exists: restore it# else: train a new model and save itsaver = tf.train.Saver()model_name = &quot;model_&quot; + str(CLASS_NUM) + &quot;class_&quot; + foldermodel = model_name + &#x27;/&#x27; + model_name + &quot;.ckpt&quot;if not os.path.exists(model): sess.run(tf.initialize_all_variables()) if not os.path.exists(model_name): os.makedirs(model_name) # with open(&#x27;out.txt&#x27;,&#x27;a&#x27;) as f: # f.write(time.strftime(&#x27;%Y-%m-%d %X&#x27;,time.localtime()) + &quot;
&quot;) # f.write(&#x27;DATA_DIR: &#x27; + DATA_DIR+ &quot;
